  "guidedPractice": {
    "title": "Guided Practice: Transmission Efficiency",
    "objective": "Apply the concept of high-voltage transmission to minimize energy waste.",
    "retrievalTextLines": [
      "Step 1: Identify the network as Transmission for long-distance bulk movement.",
      "Step 2: Select a standard UK transmission voltage (400 kV, 275 kV, or 132 kV).",
      "Step 3: Recognize that increasing voltage allows for a lower current for the same power.",
      "Step 4: Identify that lower current reduces I²R heat losses in the cables."
    ],
    "questionText": "A nuclear power station connects to the grid to supply a distant region. Explain why the voltage is stepped up to 275 kV and how this specifically affects the efficiency of the transmission lines.",
    "answerGuidance": [
      "The voltage is stepped up to 275 kV to reduce the current, which minimizes I²R heat losses in the cables during long-distance transport."
    ],
    "hint": "Think about the relationship between high voltage and current. If current (I) is low, what happens to the heat loss (I²R)?"
  },
  "practice": {
    "title": "Independent Practice: UK Grid Voltages",
    "objective": "Identify standard transmission voltages and the technical purpose of high-voltage transmission.",
    "retrievalTextLines": [
      "Standard UK Transmission Voltages: 400 kV, 275 kV, 132 kV.",
      "Primary Goal: Efficiency through the reduction of current to prevent energy waste."
    ],
    "questionText": "List the three standard UK transmission voltages and explain the main technical reason why such high voltages are required for the bulk movement of electricity across the country.",
    "answerGuidance": [
      "400 kV, 275 kV, and 132 kV; these high voltages are used to reduce the current, which minimizes I²R heat losses in the transmission network."
    ],
    "hint": "Recall the 'Big Three' voltages used on the steel pylon routes and the specific type of energy loss we aim to prevent in long-distance cables."
