{
  "integrative": {
    "title": "Integrative Close: From Source to Grid",
    "objective": "Synthesize the relationship between generation scale, transmission voltage selection, and the physics of efficiency through heat loss reduction.",
    "retrievalTextLines": [
      "Large-scale vs. Micro-generation",
      "Standard UK Transmission Voltages (400 kV, 275 kV, 132 kV)",
      "The relationship between Voltage, Current, and I²R losses"
    ],
    "questionText": "A large-scale power station is being connected to the National Grid to supply a city 150 miles away. Explain why the electricity is stepped up to a transmission voltage (such as 400 kV or 275 kV) for this journey, and contrast this with why a domestic micro-generation system, like a solar PV array, does not require these high voltages.",
    "answerGuidance": [
      "The power station uses high transmission voltages (400 kV/275 kV) to reduce the current flowing through the long-distance cables.",
      "Reducing the current is essential to minimize I²R losses, which is energy wasted as heat in the conductors over long distances.",
      "In contrast, micro-generation like solar PV is generated at the point of consumption, meaning the electricity does not travel long distances and therefore does not suffer the same scale of heat loss requiring high-voltage transmission."
    ],
    "hint": "Think about the distance the electricity travels in both scenarios and how the 'I' in I²R affects energy waste as heat."
  }
}

